  ('judicial-f0899a01-moex-00496', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲先殺A，A反抗甚鉅，甲之友人乙碰巧經過現場，立即加入甲之殺人行動，雙方基於共同殺A意思，由 乙抓住A而讓甲順利殺害A。甲、乙刑責為何？', '["甲、乙成立殺人既遂罪之共謀共同正犯", "甲、乙成立殺人既遂罪之相續共同正犯", "甲成立殺人既遂罪，乙成立殺人未遂罪", "甲成立殺人既遂罪之正犯，乙成立殺人既遂罪之幫助犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
