  ('judicial-f0899a01-moex-00498', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '緩刑期滿，緩刑之宣告未經撤銷者，原有之刑之宣告效力為何？', '["其刑之宣告以已執行論", "其刑之宣告失其效力", "其刑之宣告以受撤銷論", "其刑之宣告以赦免論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00499', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲對A使用之住宅縱火，事後反悔，打匿名電話通知消防隊，但該住宅已燒燬。有關甲之刑責，下列何者 正確？', '["甲成立放火既遂罪", "甲成立放火未遂罪之中止犯", "甲成立自首，得減輕其刑", "甲成立失火罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00500', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關自首的敘述，下列何者錯誤？', '["行為人主動向追訴機關申告自己尚未被發覺之犯罪而自願接受裁判", "自白與自首不同", "除有特別規定外，自首應減輕其刑", "不論以口頭或書面形式，皆可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00501', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲是演員，依劇本應持道具槍作出開槍朝丙擊發之動作。乙明知其事，為利用甲殺死丙，暗中將該道具槍 調包為真槍。不知情之甲仍依劇本持槍朝丙射擊，導致丙死亡。下列敘述，何者正確？', '["甲成立故意殺人既遂罪", "乙成立故意殺人既遂罪", "甲成立殺人罪之幫助犯", "乙成立殺人罪之教唆犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00502', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關故意的敘述，下列何者錯誤？', '["對於構成犯罪之事實，預見其能發生而確信其不發生者，亦屬故意", "直接故意包含認識與意欲要素", "對於構成犯罪之事實，明知並有意使其發生，為直接故意", "對於構成犯罪之事實，預見其發生而其發生並不違背其本意者，為未必故意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00503', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '公務員明知上級之命令違法，仍依所屬上級公務員命令而為其行為，其法律效果為何？', '["屬緊急避難，阻卻違法", "不得阻卻違法", "屬正當防衛，阻卻違法", "屬業務上正當行為，阻卻違法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00504', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '依刑法之規定，業務上之正當行為，其法律效果為何？', '["不罰", "免除其刑", "減輕其刑", "減輕或免除其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "54e736c03dd5", "answer_pdf_sha1": "cc4f71ea37fd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
